using UnityEngine;
using Climbing;

public class AnyRootTeleporter
{
    public static string Run()
    {
        ClimbController cc = Object.FindObjectOfType<ClimbController>();
        if (cc == null) return "No player found in scene.";

        GameObject pm = cc.gameObject;
        Transform root = pm.transform.root;

        RaycastHit hit;
        if (Physics.Raycast(root.position + Vector3.up * 5.0f, Vector3.down, out hit, 100f))
        {
            root.position = hit.point + Vector3.up * 0.1f;
            pm.transform.localPosition = Vector3.zero;
            return $"Teleported ROOT {root.name} and PlayerModel {pm.name} to ground at {hit.point}";
        }

        return "No ground found below the character root.";
    }
}
